// skip 1st line — Firefox autoconfig discards this line, so a comment goes here.
//
// palefox hash-pinning bootstrap (template) — generated by
// tools/generate-bootstrap.ts at build time into program/config.generated.js,
// which install.sh / nix copies to the Firefox install root as config.js.
//
// What this does:
//   1. Iterates <profile>/chrome/utils/, <profile>/chrome/JS/, <profile>/chrome/CSS/
//   2. SHA-256s every file found
//   3. Compares against the PINNED manifest baked in at palefox build time
//   4. Refuses to load if ANY pinned file is missing OR mismatched OR if any
//      EXTRA file is present in those directories
//   5. If clean, registers the chrome.manifest and imports boot.sys.mjs (the
//      same chain fx-autoconfig uses today)
//
// Why this is needed:
//   The stock fx-autoconfig bootstrap blindly imports whatever JS exists in
//   <profile>/chrome/JS/ and <profile>/chrome/utils/, both of which are
//   user-writable. A compromised npm package or other local-mode malware
//   can drop a .uc.js file there and get full chrome-scope JS execution on
//   next Firefox start. Hash-pinning closes that gap: only files whose
//   hashes match the manifest in this (root-owned) bootstrap are loaded.
//
// Failure modes:
//   - All pinned files missing → silent bail (palefox not installed in this profile)
//   - Some pinned files missing → loud bail via Cu.reportError (incomplete install)
//   - Hash mismatch on any pinned file → loud bail (tampering)
//   - Extra .uc.js / .uc.mjs / .sys.mjs / .uc.css file in watched dirs → loud bail

try {
  // ===========================================================================
  // PALEFOX_PINNED — generated at build time, do not edit by hand.
  // Maps "subdir/filename" → "sha256-base64hash".
  // ===========================================================================
  const PALEFOX_PINNED = __PALEFOX_PINNED__;

  const dirSvc = Cc["@mozilla.org/file/directory_service;1"]
    .getService(Ci.nsIProperties);
  const chromeDir = dirSvc.get("UChrm", Ci.nsIFile);

  if (!chromeDir.exists() || !chromeDir.isDirectory()) {
    // No chrome dir — palefox not installed here. Silent bail.
    throw new Error("palefox: no chrome dir in profile");
  }

  // SHA-256 of an nsIFile, returned as "sha256-<base64>".
  function sha256(file) {
    const stream = Cc["@mozilla.org/network/file-input-stream;1"]
      .createInstance(Ci.nsIFileInputStream);
    stream.init(file, 0x01 /* PR_RDONLY */, 0, 0);
    const hasher = Cc["@mozilla.org/security/hash;1"]
      .createInstance(Ci.nsICryptoHash);
    hasher.init(hasher.SHA256);
    hasher.updateFromStream(stream, -1);
    stream.close();
    return "sha256-" + hasher.finish(true /* base64 */);
  }

  // Resolve "utils/boot.sys.mjs" → nsIFile under chromeDir.
  function resolveRelative(relPath) {
    const file = chromeDir.clone();
    for (const part of relPath.split("/")) {
      file.append(part);
    }
    return file;
  }

  // ---------------------------------------------------------------------------
  // Check 1: every PINNED entry must exist and match its hash.
  // - 0 pinned files found → palefox not installed → silent bail
  // - some-but-not-all → suspicious incomplete state → loud bail
  // - all present but any mismatch → tampering → loud bail
  // ---------------------------------------------------------------------------
  const pinnedPaths = Object.keys(PALEFOX_PINNED);
  const missingFiles = [];
  const mismatchedFiles = [];

  for (const relPath of pinnedPaths) {
    const file = resolveRelative(relPath);
    if (!file.exists()) {
      missingFiles.push(relPath);
      continue;
    }
    const actual = sha256(file);
    const expected = PALEFOX_PINNED[relPath];
    if (actual !== expected) {
      mismatchedFiles.push({ relPath, actual, expected });
    }
  }

  if (missingFiles.length === pinnedPaths.length) {
    // Nothing installed in this profile. Silent bail.
    throw new Error("palefox: not installed in this profile");
  }
  if (missingFiles.length > 0) {
    Cu.reportError(
      "palefox: refusing to load — incomplete install, missing files:\n  " +
      missingFiles.join("\n  ")
    );
    throw new Error("palefox: incomplete install");
  }
  if (mismatchedFiles.length > 0) {
    for (const m of mismatchedFiles) {
      Cu.reportError(
        `palefox: hash mismatch on ${m.relPath}\n` +
        `  expected: ${m.expected}\n` +
        `  actual:   ${m.actual}`
      );
    }
    throw new Error("palefox: hash mismatch");
  }

  // ---------------------------------------------------------------------------
  // Check 2: every loadable file in utils/, JS/, CSS/ must be in PINNED.
  // This catches the "attacker drops evil.uc.js" case — even though pinned
  // files all check out, a stranger means fx-autoconfig's loader would load
  // it. Refuse to start the loader at all.
  //
  // Patterns mirror fx-autoconfig's own loadability filters in boot.sys.mjs.
  // Files that don't match the loadability pattern are ignored (e.g. a
  // README.md in JS/ is harmless because fx-autoconfig won't load it).
  // utils/ has no extension filter — every file there is loader machinery
  // and must be pinned.
  // ---------------------------------------------------------------------------
  const WATCHED = [
    { subdir: "utils", pattern: /./ },
    { subdir: "JS",    pattern: /^[A-Za-z0-9].*\.(uc\.js|uc\.mjs|sys\.mjs)$/i },
    { subdir: "CSS",   pattern: /^[A-Za-z0-9].*\.uc\.css$/i },
  ];
  for (const { subdir, pattern } of WATCHED) {
    const dir = chromeDir.clone();
    dir.append(subdir);
    if (!dir.exists() || !dir.isDirectory()) continue;
    const entries = dir.directoryEntries;
    while (entries.hasMoreElements()) {
      const f = entries.getNext().QueryInterface(Ci.nsIFile);
      if (!f.isFile()) continue;
      if (!pattern.test(f.leafName)) continue;
      const relPath = subdir + "/" + f.leafName;
      if (!(relPath in PALEFOX_PINNED)) {
        Cu.reportError(
          `palefox: refusing to load — unexpected file ${relPath} ` +
          `(not in pinned manifest)`
        );
        throw new Error("palefox: unexpected file");
      }
    }
  }

  // ---------------------------------------------------------------------------
  // All checks passed — chain to fx-autoconfig's loader (same path as stock
  // config.js). The chrome.manifest registers chrome:// URIs that
  // boot.sys.mjs uses to discover scripts and styles.
  // ---------------------------------------------------------------------------
  const manifest = chromeDir.clone();
  manifest.append("utils");
  manifest.append("chrome.manifest");
  if (manifest.exists()) {
    Components.manager.QueryInterface(Ci.nsIComponentRegistrar)
      .autoRegister(manifest);
    ChromeUtils.importESModule("chrome://userchromejs/content/boot.sys.mjs");
  }
} catch (ex) {
  // Errors thrown above are the normal bail path (silent or already reported).
  // Anything else is unexpected — log it so we don't fail-open silently.
  if (ex && typeof ex.message === "string"
      && !ex.message.startsWith("palefox:")) {
    Cu.reportError("palefox bootstrap unexpected error: " + ex);
  }
}
